<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        /* --- Global Reset & Variables --- */
        :root {
            --bg-dark: #2e3436;
            --fg-light: #eceff4;
            --accent-color: #88c0d0; /* Light blue/cyan for accents */
            --border-color: #5e81ac;
            --window-bg: #3b4247;
            --text-color: #d8dee9;
        }

        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
        }

        body, #desktop {
            height: 100vh;
            width: 100vw;
            background-color: var(--bg-dark);
            overflow: hidden; /* Desktop handles its own scrolling */
            position: relative;
        }

        /* --- Taskbar/Dock Styling --- */
        #taskbar {
            position: fixed;
            bottom: 0;
            left: 0;
            width: 100%;
            height: 45px;
            background-color: rgba(30, 38, 42, 0.9); /* Slightly darker than desktop */
            backdrop-filter: blur(10px);
            display: flex;
            align-items: center;
            padding: 0 15px;
            z-index: 1000;
        }

        .taskbar-button {
            background: var(--window-bg);
            color: var(--fg-light);
            border: none;
            padding: 8px 15px;
            margin-right: 10px;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.1s;
            border-radius: 6px;
            font-weight: 600;
        }

        .taskbar-button:hover {
            background-color: #4c565b;
        }

        /* --- Window Styling (General) --- */
        .window {
            position: absolute;
            top: 10%;
            left: 10%;
            width: 70vw;
            max-width: 900px;
            height: 65vh;
            min-width: 360px; /* Required minimum */
            min-height: 240px; /* Required minimum */
            background-color: var(--window-bg);
            border: 1px solid #4a555b;
            box-shadow: 0 8px 30px rgba(0, 0, 0, 0.6);
            display: flex;
            flex-direction: column;
            z-index: 900; /* Below taskbar */
            transition: transform 0.3s ease-out;
        }

        /* Window Header/Title Bar */
        .window-header {
            padding: 8px 12px;
            background-color: #4a555b;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: grab; /* Suggests drag capability */
            border-bottom: 1px solid #3c444d;
        }

        .window-title {
            font-weight: bold;
            color: var(--fg-light);
        }

        .win-close {
            background: none;
            border: none;
            color: var(--text-color);
            cursor: pointer;
            font-size: 18px;
            padding: 5px;
            transition: background-color 0.2s;
        }

        .win-close:hover {
            background-color: #6c7a83;
            border-radius: 4px;
        }

        /* Window Content Area */
        .window-content {
            flex-grow: 1;
            padding: 15px;
            overflow: auto;
            background-color: #2e3436; /* Slightly darker content background */
            color: var(--text-color);
        }

        /* --- Files App Specific Styling --- */
        #files-window .window-content {
            display: flex;
            flex-direction: column;
        }

        #files-path {
            padding: 10px 0;
            font-size: 1.1em;
            color: var(--accent-color);
            border-bottom: 1px solid #4a555b;
            margin-bottom: 10px;
        }

        #files-controls {
            display: flex;
            align-items: center;
            gap: 10px;
            padding-bottom: 10px;
            border-bottom: 1px solid #4a555b;
            margin-bottom: 10px;
        }

        #files-up {
            background: var(--accent-color);
            color: var(--bg-dark);
            padding: 6px 12px;
            border: none;
            cursor: pointer;
            border-radius: 4px;
            transition: opacity 0.2s;
        }

        #files-up:disabled {
            opacity: 0.5;
            cursor: not-allowed;
        }

        #files-listing {
            display: flex;
            flex-direction: column;
            gap: 8px;
            padding-top: 10px;
        }

        .fs-item {
            display: flex;
            align-items: center;
            padding: 8px;
            cursor: pointer;
            border-radius: 4px;
            transition: background-color 0.2s, color 0.2s;
        }

        .fs-item:hover {
            background-color: #3c444d;
        }

        .fs-item[data-type="folder"] {
            font-weight: bold;
            color: var(--accent-color);
        }

        .fs-item[data-type="file"] {
            color: var(--text-color);
        }

        /* --- Notepad App Specific Styling --- */
        #notepad-window .window-content {
            display: flex;
            flex-direction: column;
            height: 100%; /* Ensure content area fills remaining space */
            padding: 0;
        }

        #tabs {
            display: flex;
            background-color: #3c444d;
            border-bottom: 1px solid #4a555b;
            height: 30px; /* Fixed height for tab strip */
            padding-left: 5px;
        }

        .tab {
            background-color: var(--window-bg);
            padding: 8px 15px;
            cursor: pointer;
            border-right: 1px solid #4a555b;
            display: flex;
            align-items: center;
            font-size: 0.9em;
            user-select: none;
        }

        .tab.active {
            background-color: var(--window-bg);
            border-bottom: 1px solid #2e3436; /* Blends into editor */
        }

        #editor {
            flex-grow: 1;
            width: 100%;
            height: calc(100% - 30px); /* Full height minus tab strip */
            padding: 15px;
            background-color: #2e3436;
            border: none;
            resize: none;
            color: var(--text-color);
            outline: none;
        }

    </style>
</head>
<body>

    <!-- DESKTOP ROOT -->
    <div id="desktop">

        <!-- 1. FILES WINDOW -->
        <div id="files-window" class="window hidden">
            <div class="window-header">
                <span class="window-title">File Explorer</span>
                <div>
                    <button class="win-close" data-target="#files-window">&times;</button>
                </div>
            </div>
            <div class="window-content">
                <div id="files-path">/</div>

                <div id="files-controls">
                    <button id="files-up" disabled>Up</button>
                    <!-- Future controls like New Folder button could go here -->
                </div>

                <div id="files-listing">
                    <!-- Files and folders will be rendered here by JS -->
                </div>
            </div>
        </div>

        <!-- 2. NOTEPAD WINDOW -->
        <div id="notepad-window" class="window hidden">
            <div class="window-header">
                <span class="window-title">Notepad</span>
                <div>
                    <button class="win-close" data-target="#notepad-window">&times;</button>
                </div>
            </div>
            <div class="window-content">
                <!-- Tab Strip -->
                <div id="tabs">
                    <!-- Tabs will be injected here -->
                </div>

                <!-- Editor Area -->
                <textarea id="editor" placeholder="Start typing..."></textarea>
            </div>
        </div>

    </div>

    <!-- TASKBAR/DOCK -->
    <div id="taskbar">
        <button class="taskbar-button" id="open-files">📁 Files</button>
        <button class="taskbar-button" id="open-notepad">📝 Notepad</button>
    </div>

    <script>
        // ==================================================
        // CORE UTILITIES & STATE MANAGEMENT
        // ==================================================

        const DESKTOP = document.getElementById('desktop');
        const TASKBAR = document.getElementById('taskbar');

        /**
         * Toggles the visibility of a window element.
         * @param {string} targetId - The ID of the window element.
         */
        function toggleWindow(targetId) {
            const windowEl = document.querySelector(targetId);
            if (windowEl) {
                const isHidden = windowEl.classList.contains('hidden');
                if (isHidden) {
                    windowEl.classList.remove('hidden');
                    // Special initialization for files app when opening
                    if (targetId === '#files-window') {
                        initializeFilesystem();
                    }
                } else {
                    windowEl.classList.add('hidden');
                }
            }
        }

        // ==================================================
        // 1. FILES APP LOGIC
        // ==================================================

        const filesApp = {
            rootElement: document.getElementById('files-listing'),
            pathDisplay: document.getElementById('files-path'),
            upButton: document.getElementById('files-up'),
            currentPath: '/',
            filesystem: {
                '/': {
                    type: 'folder',
                    children: {
                        'bin': { type: 'folder', children: {} },
                        'etc': { type: 'folder', children: {} },
                        'home': { type: 'folder', children: {
                            'user': { type: 'folder', children: {
                                'Documents': { type: 'folder', children: {} },
                                'Downloads': { type: 'folder', children: {} },
                                'Pictures': { type: 'folder', children: {} },
                                'readme.txt': { type: 'file' }
                            }}
                        }},
                        'usr': { type: 'folder', children: {} },
                        'var': { type: 'folder', children: {} }
                    }
                },
                '/home/user/Documents': {
                    type: 'folder',
                    children: {
                        'Project Alpha.doc': { type: 'file' },
                        'Notes': { type: 'folder', children: {} }
                    }
                },
                 '/home/user/Downloads': {
                    type: 'folder',
                    children: {
                        'setup.zip': { type: 'file' }
                    }
                }
            },

            /** Gets the directory object for a given path segment */
            getDir(path) {
                let current = this.filesystem;
                const segments = path.split('/').filter(s => s); // Filter out empty strings from leading/trailing slashes
                let tempPath = '';
                for (const segment of segments) {
                    if (!current || !current[segment] || current[segment].type !== 'folder') {
                        return null;
                    }
                    tempPath += '/' + segment;
                    // This is a simplified traversal for the static structure
                    if (this.filesystem['/' + tempPath]) {
                         current = this.filesystem['/' + tempPath];
                    } else if (this.filesystem[tempPath] && this.filesystem[tempPath].type === 'folder') {
                        current = this.filesystem[tempPath];
                    } else {
                        return null; // Path segment not found or is a file
                    }
                }
                return current;
            },

            /** Renders the contents of the current directory */
            renderListing() {
                this.rootElement.innerHTML = '';
                const dirData = this.getDir(this.currentPath);

                if (!dirData || !dirData.children) {
                    this.rootElement.innerHTML = '<p style="padding: 20px; color: var(--text-color);">This directory is empty.</p>';
                    return;
                }

                const sortedItems = Object.keys(dirData.children).sort((a, b) => {
                    // Folders first, then files (simple heuristic)
                    const typeA = dirData.children[a].type;
                    const typeB = dirData.children[b].type;

                    if (typeA === 'folder' && typeB !== 'folder') return -1;
                    if (typeA !== 'folder' && typeB === 'folder') return 1;
                    return a.localeCompare(b);
                });


                sortedItems.forEach(name => {
                    const item = dirData.children[name];
                    const fullPath = this.currentPath === '/' ? `/${name}` : `${this.currentPath}/${name}`;

                    const itemEl = document.createElement('div');
                    itemEl.className = 'fs-item';
                    itemEl.setAttribute('data-type', item.type);
                    itemEl.dataset.path = fullPath;

                    let icon = '';
                    if (item.type === 'folder') {
                        icon = '📁 ';
                    } else if (item.type === 'file') {
                        icon = '📄 ';
                    }

                    itemEl.innerHTML = `${icon}${name}`;
                    this.rootElement.appendChild(itemEl);
                });

                // Re-attach event listeners after rendering
                document.querySelectorAll('.fs-item').forEach(el => {
                    el.addEventListener('dblclick', (e) => this.handleDoubleClick(e.currentTarget));
                });
            },

            /** Updates the path display and button state */
            updatePathDisplay() {
                this.pathDisplay.textContent = this.currentPath;
                const segments = this.currentPath.split('/').filter(s => s);
                if (segments.length > 1) {
                    this.upButton.disabled = false;
                } else {
                    this.upButton.disabled = true;
                }
            },

            /** Handles navigation into a folder */
            navigateToFolder(path) {
                // Check if the target path is actually a folder in our static structure
                const dirData = this.getDir(path);
                if (dirData && dirData.type === 'folder') {
                    this.currentPath = path;
                    this.renderListing();
                    this.updatePathDisplay();
                } else {
                    console.warn(`Attempted to navigate to non-existent or file path: ${path}`);
                }
            },

            /** Handles double-click events on items */
            handleDoubleClick(itemEl) {
                const fullPath = itemEl.dataset.path;
                const type = itemEl.dataset.type;

                if (type === 'folder') {
                    this.navigateToFolder(fullPath);
                } else if (type === 'file') {
                    // Simple file action: alert or open in a simulated viewer
                    alert(`[File Opened]: ${fullPath}. This is a static view.`);
                }
            },

            /** Handles clicking the Up button */
            goUp() {
                if (this.currentPath === '/') return;

                // Remove the last segment
                let newPath = this.currentPath.substring(0, this.currentPath.lastIndexOf('/'));

                // Handle case where we go up from /home/user to /home
                if (newPath === '') {
                    this.currentPath = '/';
                } else if (!newPath.endsWith('/') && newPath !== '/') {
                     // Ensure path ends with a slash unless it's root
                    newPath += '/';
                } else {
                    this.currentPath = newPath;
                }

                this.renderListing();
                this.updatePathDisplay();
            },

            /** Initialization function */
            initializeFilesystem() {
                // Reset state and render initial view
                this.currentPath = '/';
                this.renderListing();
                this.updatePathDisplay();
            }
        };


        // ==================================================
        // 2. NOTEPAD APP LOGIC (Persistence Required)
        // ==================================================

        const notepadApp = {
            editorEl: document.getElementById('editor'),
            tabsContainer: document.getElementById('tabs'),
            activeTabId: null,
            tabData: {}, // Stores content for each tab ID
            STORAGE_KEY: 'desktop_notepad_state',

            /** Loads state from localStorage or initializes default tabs */
            loadState() {
                const savedState = localStorage.getItem(this.STORAGE_KEY);
                if (savedState) {
                    try {
                        const data = JSON.parse(savedState);
                        this.tabData = data.tabs || {};
                        // If no tabs were explicitly loaded, create a default one
                        if (Object.keys(this.tabData).length === 0) {
                            this.createTab('Welcome Note', 'This is your persistent notepad.');
                        } else {
                             // Activate the first tab found in storage
                            const firstTabId = Object.keys(this.tabData)[0];
                            if (firstTabId) this.switchTab(firstTabId);
                        }

                    } catch (e) {
                        console.error("Failed to load notepad state:", e);
                        this.createTab('Welcome Note', 'Could not restore previous session.');
                    }
                } else {
                    // Initial setup if nothing is saved
                    this.createTab('Welcome Note', 'This tab content persists across reloads!');
                }
            },

            /** Saves the current state of all tabs to localStorage */
            saveState() {
                const dataToSave = {
                    tabs: {}
                };
                for (const id in this.tabData) {
                    dataToSave.tabs[id] = { content: this.tabData[id].content };
                }
                localStorage.setItem(this.STORAGE_KEY, JSON.stringify(dataToSave));
            },

            /** Creates a new tab element and updates internal state */
            createTab(title, initialContent = '') {
                const tabId = `tab-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;

                // Update data model
                this.tabData[tabId] = { title: title, content: initialContent };

                // Create DOM elements
                const tabEl = document.createElement('div');
                tabEl.className = 'tab';
                tabEl.id = `tab-${tabId}`;
                tabEl.textContent = title;
                tabEl.dataset.tabId = tabId;
                this.tabsContainer.appendChild(tabEl);

                // Create content area (textarea)
                const textareaEl = document.createElement('textarea');
                textareaEl.id = `editor-${tabId}`;
                textareaEl.value = initialContent;
                textareaEl.placeholder = 'Start typing...';
                document.getElementById('editor').parentNode.appendChild(textareaEl);

                // Update global references (since we are dynamically adding the editor)
                this.editorEl.id = `editor-${tabId}`; // Overwrite placeholder ID for simplicity in this single-file setup
                this.editorEl.value = initialContent; 

                // Activate and save state
                this.switchTab(tabId);
            },

            /** Switches the active tab */
            switchTab(tabId) {
                if (this.activeTabId === tabId) return;

                // 1. Deactivate old tab elements
                document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                const oldEditor = document.getElementById(`editor-${this.activeTabId}`);
                if (oldEditor) {
                    oldEditor.readOnly = true; // Simulate losing focus/activity
                }

                // 2. Activate new tab elements
                document.getElementById(`tab-${tabId}`).classList.add('active');
                const newEditor = document.getElementById(`editor-${tabId}`);
                if (newEditor) {
                    newEditor.readOnly = false;
                    newEditor.focus();
                }

                this.activeTabId = tabId;
            },

            /** Handles content changes and saves state */
            handleInput(event) {
                const newContent = event.target.value;
                if (this.activeTabId && this.tabData[this.activeTabId]) {
                    this.tabData[this.activeTabId].content = newContent;
                    // Debounce saving to localStorage for performance
                    clearTimeout(this._saveTimer);
                    this._saveTimer = setTimeout(() => this.saveState(), 500);
                }
            },

            /** Initializes all listeners and loads state */
            init() {
                this.loadState();

                // Event listener for tab clicks
                this.tabsContainer.addEventListener('click', (e) => {
                    const targetTab = e.target.closest('.tab');
                    if (targetTab && targetTab.dataset.tabId) {
                        this.switchTab(targetTab.dataset.tabId);
                    }
                });

                // Event listener for editor input (delegated to the single textarea element)
                const editor = document.getElementById('editor');
                if (editor) {
                     editor.addEventListener('input', this.handleInput.bind(this));
                }
            }
        };


        // ==================================================
        // 3. INITIALIZATION & EVENT BINDING
        // ==================================================

        document.addEventListener('DOMContentLoaded', () => {
            // --- Window Close Listeners ---
            DESKTOP.querySelectorAll('.win-close').forEach(button => {
                button.addEventListener('click', (e) => {
                    const targetId = e.target.dataset.target;
                    if (targetId) {
                        toggleWindow(targetId);
                    }
                });
            });

            // --- Taskbar Launchers ---
            document.getElementById('open-files').addEventListener('click', () => toggleWindow('#files-window'));
            document.getElementById('open-notepad').addEventListener('click', () => {
                 toggleWindow('#notepad-window');
                 // Ensure notepad state is loaded/initialized when opened
                 if (!notepadApp.activeTabId) {
                     notepadApp.init(); 
                 }
            });

            // --- Files App Listeners ---
            document.getElementById('files-up').addEventListener('click', () => filesApp.goUp());


            // --- Notepad Initialization (Must run after DOM is ready) ---
            notepadApp.init();
        });

    </script>
</body>
</html>
